import numpy as np
from itertools import combinations

def construct():
    """
    Ultra-aggressive asymmetric structure with systematic plateau mining.

    Key strategies:
    1. Non-uniform 5-layer hierarchy (sizes 11,11,11,10,10) with asymmetric
       between-layer densities to maximize N++ / N+ imbalance.
    2. Circulant base {1..8} guarantees min out-degree.
    3. Within-layer asymmetric offsets (not regular) break algebraic symmetry.
    4. Intensive multi-flip plateau search: single -> pair -> triple -> quad
       flips, accepting all neutral moves (<=) to traverse connected components
       of equal-score configurations.
    5. Strict iteration budgeting with early termination only after multiple
       plateau rounds fail to improve.
    """
    rng = np.random.default_rng(789)
    N = 53
    A = np.zeros((N, N), dtype=np.int8)

    # Phase 1: Circulant skeleton {1..8}
    for i in range(N):
        for d in range(1, 9):
            A[i, (i + d) % N] = 1

    # Phase 2: 5-layer asymmetric hierarchy
    layer_sizes = [11, 11, 11, 10, 10]
    layer_starts = np.cumsum([0] + layer_sizes[:-1]).tolist()

    # Within-layer: add asymmetric non-circulant arcs
    for layer_idx in range(5):
        start, size = layer_starts[layer_idx], layer_sizes[layer_idx]
        for u in range(start, start + size):
            # Use prime-offset-like asymmetric targets
            for offset in [7, 13, 17, 19, 23]:
                v_global = u + offset
                if start <= (v_global % N) < start + size:
                    v = v_global % N
                else:
                    v = (u + offset) % N
                if start <= v < start + size and not A[u, v] and not A[v, u]:
                    A[u, v] = 1

    # Between-layer: create directed flow with skip patterns
    for layer_idx in range(5):
        start, size = layer_starts[layer_idx], layer_sizes[layer_idx]

        # Forward to next layer: VERY dense (break circulant plateau)
        next_idx = (layer_idx + 1) % 5
        next_start, next_size = layer_starts[next_idx], layer_sizes[next_idx]

        for u in range(start, start + size):
            for v in range(next_start, next_start + next_size):
                if not A[u, v] and not A[v, u]:
                    if rng.random() < 0.55:  # Very dense
                        A[u, v] = 1

        # Skip-1: moderate density (feedback-like)
        skip_idx = (layer_idx + 2) % 5
        skip_start, skip_size = layer_starts[skip_idx], layer_sizes[skip_idx]

        for u in range(start, start + size):
            if rng.random() < 0.18:
                v = rng.integers(skip_start, skip_start + skip_size)
                if not A[u, v] and not A[v, u]:
                    A[u, v] = 1

        # Skip-2: sparse
        skip2_idx = (layer_idx + 3) % 5
        skip2_start, skip2_size = layer_starts[skip2_idx], layer_sizes[skip2_idx]

        for u in range(start, start + size):
            if rng.random() < 0.08:
                v = rng.integers(skip2_start, skip2_start + skip2_size)
                if not A[u, v] and not A[v, u]:
                    A[u, v] = 1

    def score_call(mat):
        result = score(mat)
        return result[0] if result is not None else float('inf')

    best_score_val = score_call(A)
    iteration = 0
    max_iterations = 4000
    plateau_no_improve = 0
    max_no_improve_rounds = 180

    while iteration < max_iterations and plateau_no_improve < max_no_improve_rounds:
        round_improved = False

        # Phase A: Single-arc flips (most common)
        for _ in range(min(500, max_iterations - iteration)):
            i = rng.integers(N)
            j = rng.integers(N)
            if i == j:
                continue

            old = int(A[i, j])
            if old == 1:
                A[i, j] = 0
            else:
                if A[j, i]:
                    continue
                A[i, j] = 1

            new_score = score_call(A)
            iteration += 1

            if new_score <= best_score_val:
                best_score_val = new_score
                round_improved = True
                plateau_no_improve = 0
            else:
                A[i, j] = old

            if iteration >= max_iterations:
                break

        # Phase B: Paired flips (systematic plateau traversal)
        if plateau_no_improve >= 25 and iteration < max_iterations - 200:
            for _ in range(min(350, max_iterations - iteration)):
                i1, j1 = rng.integers(N), rng.integers(N)
                i2, j2 = rng.integers(N), rng.integers(N)

                if i1 == j1 or i2 == j2 or (i1, j1) == (i2, j2):
                    continue

                old1, old2 = int(A[i1, j1]), int(A[i2, j2])

                if old1 == 1:
                    A[i1, j1] = 0
                else:
                    if A[j1, i1]:
                        continue
                    A[i1, j1] = 1

                if old2 == 1:
                    A[i2, j2] = 0
                else:
                    if A[j2, i2]:
                        A[i1, j1] = old1
                        continue
                    A[i2, j2] = 1

                new_score = score_call(A)
                iteration += 1

                if new_score <= best_score_val:
                    best_score_val = new_score
                    round_improved = True
                    plateau_no_improve = 0
                else:
                    A[i1, j1] = old1
                    A[i2, j2] = old2

                if iteration >= max_iterations:
                    break

        # Phase C: Triple flips (deep plateau mining)
        if plateau_no_improve >= 60 and iteration < max_iterations - 150:
            for _ in range(min(250, max_iterations - iteration)):
                indices = rng.choice(N, 6, replace=False)
                i1, j1, i2, j2, i3, j3 = indices

                olds = [int(A[i1, j1]), int(A[i2, j2]), int(A[i3, j3])]
                pairs = [(i1, j1), (i2, j2), (i3, j3)]

                valid = True
                for idx, (ii, jj) in enumerate(pairs):
                    if olds[idx] == 1:
                        A[ii, jj] = 0
                    else:
                        if A[jj, ii]:
                            valid = False
                            break
                        A[ii, jj] = 1

                if not valid:
                    for idx, (ii, jj) in enumerate(pairs):
                        A[ii, jj] = olds[idx]
                    continue

                new_score = score_call(A)
                iteration += 1

                if new_score <= best_score_val:
                    best_score_val = new_score
                    round_improved = True
                    plateau_no_improve = 0
                else:
                    for idx, (ii, jj) in enumerate(pairs):
                        A[ii, jj] = olds[idx]

                if iteration >= max_iterations:
                    break

        # Phase D: Quad flips (extreme plateau)
        if plateau_no_improve >= 100 and iteration < max_iterations - 100:
            for _ in range(min(150, max_iterations - iteration)):
                indices = rng.choice(N, 8, replace=False)
                pairs = [(indices[2*i], indices[2*i+1]) for i in range(4)]

                olds = [int(A[ii, jj]) for ii, jj in pairs]

                valid = True
                for idx, (ii, jj) in enumerate(pairs):
                    if olds[idx] == 1:
                        A[ii, jj] = 0
                    else:
                        if A[jj, ii]:
                            valid = False
                            break
                        A[ii, jj] = 1

                if not valid:
                    for idx, (ii, jj) in enumerate(pairs):
                        A[ii, jj] = olds[idx]
                    continue

                new_score = score_call(A)
                iteration += 1

                if new_score <= best_score_val:
                    best_score_val = new_score
                    round_improved = True
                    plateau_no_improve = 0
                else:
                    for idx, (ii, jj) in enumerate(pairs):
                        A[ii, jj] = olds[idx]

                if iteration >= max_iterations:
                    break

        if not round_improved:
            plateau_no_improve += 1
        else:
            plateau_no_improve = 0

    return A
